### Sauberes Programm ###
def combinations(desired_length):
    nucleotides=['A','T','G','C']   #Die möglichen Nukleotide, sie auf eine andere Base folgen könnten
    combs=['A','T','G','C'] #Zielliste (Hauptspeicher) für die generierten Kombinationen
    actual_length=1
    while actual_length<desired_length: #Solange die kombinationen noch kleiner sind, als die Wunschlänge:
        new_combs=[]    #Temporärer Speicher für neue Kombinationen wird leer erzeugt
        for i in combs: #Für alle Kombinationen aus der vorherigen Iteration
            for j in nucleotides:   #Für alle 4 möglichen Nukleotide, die als nächstes kommen könnten
                new_combs.append(i+j)   #Die möglichen nukleotide werden angehängt und die neu erstellten Kombinationen werden im temporären Speicher new_combs angelegt
        combs=new_combs     #Die neuen kombinationen werden im Haupt-Speicher combs abgelegt
        actual_length +=1   #Die Laufvariable für die aktuelle Länge der Kombinationen im Hauptspeicher wird um 1 erhöht
    return(combs)

def motives(DNA, motive_length):
    ammounts={}
    for comb in combinations(motive_length):
        ammounts.update({comb:0})
    for i in range(len(DNA)-(motive_length-1)):
        motive=DNA[i:i+motive_length]
        ammounts.update({motive:ammounts.get(motive)+1})
    return(ammounts)

def visualized_motives(DNA, motive_length):
    ammounts=motives(DNA, motive_length)
    for i in ammounts.keys():
        print(i+': '+ (ammounts[i]*'-')+' '+str(ammounts[i]))

pUC4K = ''
HIV = ''
visualized_motives(HIV, 4)